	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		bestAssignIdx := -1
		bestDeltaCost := 0.0
		foundFeasible := false

		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
			currentAssign := &dispatch.Assigns[assignIdx]

			if assignIdx >= dispatch.AssignsLen && currentAssign.StationsLen == 0 {
				continue
			}

			savedCost := currentAssign.Cost
			savedStationsLen := currentAssign.StationsLen
			var savedStations [MAXSTATIONS]Station
			copy(savedStations[:], currentAssign.Stations[:savedStationsLen])

			insertOK := currentAssign.AddShip(shipID, ori, des)
			if !insertOK {
				currentAssign.Cost = savedCost
				currentAssign.StationsLen = savedStationsLen
				copy(currentAssign.Stations[:], savedStations[:savedStationsLen])
				continue
			}

			oldCost := savedCost
			currentAssign.GenRoute()
			newCost := currentAssign.Cost

			if newCost < 0 || oldCost < 0 {
				currentAssign.RemoveShip(shipID)
				currentAssign.Cost = savedCost
				currentAssign.StationsLen = savedStationsLen
				copy(currentAssign.Stations[:], savedStations[:savedStationsLen])
				if currentAssign.StationsLen > 0 {
					currentAssign.GenRoute()
				}
				continue
			}

			deltaCost := newCost - oldCost
			currentAssign.RemoveShip(shipID)
			currentAssign.Cost = savedCost
			currentAssign.StationsLen = savedStationsLen
			copy(currentAssign.Stations[:], savedStations[:savedStationsLen])
			if currentAssign.StationsLen > 0 {
				currentAssign.GenRoute()
			}

			if !foundFeasible || deltaCost < bestDeltaCost {
				foundFeasible = true
				bestDeltaCost = deltaCost
				bestAssignIdx = assignIdx
			}
		}

		targetAssignIdx := bestAssignIdx
		if !foundFeasible {
			targetAssignIdx = dispatch.AssignsLen
			if targetAssignIdx >= MAXASSIGNS {
				targetAssignIdx = MAXASSIGNS - 1
			}
		}

		targetAssign := &dispatch.Assigns[targetAssignIdx]
		inserted := targetAssign.AddShip(shipID, ori, des)
		if inserted {
			targetAssign.GenRoute()
			if targetAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = targetAssignIdx + 1
			}
		} else {
			if targetAssignIdx < MAXASSIGNS-1 {
				nextIdx := targetAssignIdx + 1
				for nextIdx < MAXASSIGNS {
					candidate := &dispatch.Assigns[nextIdx]
					if candidate.AddShip(shipID, ori, des) {
						candidate.GenRoute()
						if nextIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = nextIdx + 1
						}
						break
					}
					nextIdx++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

